class BitVectorFreeSpace:
    def __init__(self, total_blocks):
        self.total_blocks = total_blocks
        # 0 = free, 1 = allocated
        self.bitmap = [0] * total_blocks

    def allocate_blocks(self, num_blocks):
        """Find consecutive free blocks and allocate them"""
        start_block = -1
        consecutive_free = 0

        for i in range(self.total_blocks):
            if self.bitmap[i] == 0:
                consecutive_free += 1
                if consecutive_free == 1:
                    start_block = i
                if consecutive_free == num_blocks:
                    # Found enough space, mark as allocated
                    for j in range(start_block, i + 1):
                        self.bitmap[j] = 1
                    return start_block
            else:
                consecutive_free = 0
                start_block = -1

        return -1  # No consecutive space found

    def deallocate_blocks(self, start_block, num_blocks):
        """Mark blocks as free in bitmap"""
        for i in range(start_block, start_block + num_blocks):
            self.bitmap[i] = 0

    def get_free_blocks_count(self):
        """Count total free blocks"""
        return self.bitmap.count(0)

    def display_bitmap(self):
        """Visual representation of disk allocation"""
        return ''.join(['.' if b == 0 else 'X' for b in self.bitmap])

# Example usage
fs = BitVectorFreeSpace(20)
print("Initial:", fs.display_bitmap())
print("Free blocks:", fs.get_free_blocks_count())

# Allocate 3 blocks
pos = fs.allocate_blocks(3)
print(f"Allocated at position {pos}: {fs.display_bitmap()}")

# Allocate 2 more blocks
pos2 = fs.allocate_blocks(2)
print(f"Allocated at position {pos2}: {fs.display_bitmap()}")

# Free first allocation
fs.deallocate_blocks(pos, 3)
print(f"After freeing: {fs.display_bitmap()}")
